"""FastAPI exceptions — HTTPException and validation errors."""
from __future__ import annotations

from typing import Any, Dict, Optional, Sequence, Union

from starlette.exceptions import HTTPException as StarletteHTTPException


class HTTPException(StarletteHTTPException):
    """
    An HTTP exception you can raise to return an HTTP error response.

    Usage::

        from fastapi import HTTPException

        @app.get("/users/{id}")
        def get_user(id: int):
            if id not in users_db:
                raise HTTPException(status_code=404, detail="User not found")
            return users_db[id]
    """

    def __init__(
        self,
        status_code: int,
        detail: Any = None,
        headers: Optional[Dict[str, str]] = None,
    ) -> None:
        super().__init__(status_code=status_code, detail=detail)
        self.headers = headers

    def __repr__(self) -> str:
        class_name = self.__class__.__name__
        return f"{class_name}(status_code={self.status_code!r}, detail={self.detail!r})"


class RequestValidationError(Exception):
    """Raised when request body fails Pydantic validation."""

    def __init__(self, errors: Sequence[Any], *, body: Any = None) -> None:
        self.errors = errors
        self.body = body

    def error_count(self) -> int:
        return len(self.errors)


class ResponseValidationError(Exception):
    """Raised when response body fails Pydantic validation."""

    def __init__(self, errors: Sequence[Any], *, body: Any = None) -> None:
        self.errors = errors
        self.body = body


class WebSocketRequestValidationError(Exception):
    """Raised when WebSocket message fails validation."""

    def __init__(self, errors: Sequence[Any]) -> None:
        self.errors = errors
